static double[,] ToDoubleArray(List<(double X, double Y)> points)
{
    int n = points?.Count ?? throw new ArgumentNullException(nameof(points));
    var result = new double[n, 2];
    for (int i = 0; i < n; i++)
    {
        result[i, 0] = points[i].X; // X
        result[i, 1] = points[i].Y; // Y
    }
    return result;
}
var doubles = ToDoubleArray(arbitrary);
static byte[] SerializeAndCompress(double[,] data)
{
    int n = data.GetLength(0);
    using var ms = new MemoryStream();
    using (var gzip = new GZipStream(ms, CompressionLevel.SmallestSize, leaveOpen: true))
    using (var bw = new BinaryWriter(gzip))
    {
        bw.Write(n);
        for (int i = 0; i < n; i++)
        {
            bw.Write(data[i, 0]); // x
            bw.Write(data[i, 1]); // y
        }
    }
    return ms.ToArray();
}
static double[,] DecompressAndDeserialize(byte[] data)
{
    using var ms = new MemoryStream(data);
    using var gzip = new GZipStream(ms, CompressionMode.Decompress);
    using var br = new BinaryReader(gzip);
    int rows = br.ReadInt32();
    var result = new double[rows, 2];
    for (int i = 0; i < rows; i++)
    {
        result[i, 0] = br.ReadDouble(); // x
        result[i, 1] = br.ReadDouble(); // y
    }
    return result;
}
static string SerializeToBase64(byte[] data) => Convert.ToBase64String(data);
static double[,] DeserializeFromBase64(string base64)
{
    byte[] data = Convert.FromBase64String(base64);
    return DecompressAndDeserialize(data);
}
